   141→#define MAX_TYPED_VALUE_CHARS 100
   142→
   143→static void sprint_typed_value(char* buffer,
   144→                               size_t size,
   145→                               const TypedValue* tv) {
   146→  switch (tv->type) {
   147→    case Type::I32:
   148→      snprintf(buffer, size, "i32:%u", tv->value.i32);
   149→      break;
   150→
   151→    case Type::I64:
   152→      snprintf(buffer, size, "i64:%" PRIu64, tv->value.i64);
   153→      break;
   154→
   155→    case Type::F32: {
   156→      float value;
   157→      memcpy(&value, &tv->value.f32_bits, sizeof(float));
   158→      snprintf(buffer, size, "f32:%f", value);
   159→      break;
   160→    }
   161→
   162→    case Type::F64: {
   163→      double value;
   164→      memcpy(&value, &tv->value.f64_bits, sizeof(double));
   165→      snprintf(buffer, size, "f64:%f", value);
   166→      break;
   167→    }
   168→
   169→    default:
   170→      assert(0);
   171→      break;
   172→  }
   173→}
   174→
   175→static void print_typed_value(const TypedValue* tv) {
   176→  char buffer[MAX_TYPED_VALUE_CHARS];
   177→  sprint_typed_value(buffer, sizeof(buffer), tv);
   178→  printf("%s", buffer);
   179→}
   180→
   181→static void print_typed_value_vector(const std::vector<TypedValue>& values) {
   182→  for (size_t i = 0; i < values.size(); ++i) {
   183→    print_typed_value(&values[i]);
   184→    if (i != values.size() - 1)
   185→      printf(", ");
   186→  }
   187→}
   188→
   189→static void print_interpreter_result(const char* desc,
   190→                                     interpreter::Result iresult) {
   191→  printf("%s: %s\n", desc, s_trap_strings[static_cast<size_t>(iresult)]);
   192→}
   193→
   194→static void print_call(string_view module_name,
   195→                       string_view func_name,
   196→                       const std::vector<TypedValue>& args,
   197→                       const std::vector<TypedValue>& results,
   198→                       interpreter::Result iresult) {
   199→  if (!module_name.empty())
   200→    printf(PRIstringview ".", WABT_PRINTF_STRING_VIEW_ARG(module_name));
   201→  printf(PRIstringview "(", WABT_PRINTF_STRING_VIEW_ARG(func_name));
   202→  print_typed_value_vector(args);
   203→  printf(") =>");
   204→  if (iresult == interpreter::Result::Ok) {
   205→    if (results.size() > 0) {
   206→      printf(" ");
   207→      print_typed_value_vector(results);
   208→    }
   209→    printf("\n");
   210→  } else {
   211→    print_interpreter_result(" error", iresult);
   212→  }
   213→}
   214→
   215→static interpreter::Result run_function(Thread* thread,
   216→                                        Index func_index,
   217→                                        const std::vector<TypedValue>& args,
   218→                                        std::vector<TypedValue>* out_results) {
   219→  return s_trace ? thread->TraceFunction(func_index, s_stdout_stream.get(),
   220→                                         args, out_results)
   221→                 : thread->RunFunction(func_index, args, out_results);
   222→}
   223→
   224→static interpreter::Result run_start_function(Thread* thread,
   225→                                              DefinedModule* module) {
   226→  if (module->start_func_index == kInvalidIndex)
   227→    return interpreter::Result::Ok;
   228→
   229→  if (s_trace)
   230→    printf(">>> running start function:\n");
   231→  std::vector<TypedValue> args;
   232→  std::vector<TypedValue> results;
   233→  interpreter::Result iresult =
   234→      run_function(thread, module->start_func_index, args, &results);
   235→  assert(results.size() == 0);
   236→  return iresult;
   237→}
   238→
   239→static interpreter::Result run_export(Thread* thread,
   240→                                      const Export* export_,
   241→                                      const std::vector<TypedValue>& args,
   242→                                      std::vector<TypedValue>* out_results) {
   243→  if (s_trace) {
   244→    printf(">>> running export \"" PRIstringview "\":\n",
   245→           WABT_PRINTF_STRING_VIEW_ARG(export_->name));
   246→  }
   247→
   248→  assert(export_->kind == ExternalKind::Func);
   249→  return run_function(thread, export_->index, args, out_results);
   250→}
   251→
   252→static interpreter::Result run_export_by_name(
   253→    Thread* thread,
   254→    Module* module,
   255→    string_view name,
   256→    const std::vector<TypedValue>& args,
   257→    std::vector<TypedValue>* out_results,
   258→    RunVerbosity verbose) {
   259→  Export* export_ = module->GetExport(name);
   260→  if (!export_)
   261→    return interpreter::Result::UnknownExport;
   262→  if (export_->kind != ExternalKind::Func)
   263→    return interpreter::Result::ExportKindMismatch;
   264→  return run_export(thread, export_, args, out_results);
   265→}
   266→
   267→static interpreter::Result get_global_export_by_name(
   268→    Thread* thread,
   269→    Module* module,
   270→    string_view name,
   271→    std::vector<TypedValue>* out_results) {
   272→  Export* export_ = module->GetExport(name);
   273→  if (!export_)
   274→    return interpreter::Result::UnknownExport;
   275→  if (export_->kind != ExternalKind::Global)
   276→    return interpreter::Result::ExportKindMismatch;
   277→
   278→  Global* global = thread->env()->GetGlobal(export_->index);
   279→  out_results->clear();
   280→  out_results->push_back(global->typed_value);
   281→  return interpreter::Result::Ok;
   282→}
   283→
